        std::env::set_var("NO_COLOR", "1");
        assert!(matches!(ColorProfile::detect(), ColorProfile::Mono));
        std::env::remove_var("NO_COLOR");
    }

    #[test]
    fn wcag_aa_contrast_check() {
        // 4.5:1 ratio for normal text
        let white = PackedRgba::rgb(255, 255, 255);
        let black = PackedRgba::rgb(0, 0, 0);
        let ratio = contrast_ratio(white, black);
        assert!(ratio >= 4.5);
    }

    #[test]
    fn semantic_colors_meet_wcag_aa() {
        let bg = bg::BASE.resolve();

        for color in [status::OPEN, status::BLOCKED, priority::CRITICAL] {
            let fg = color.resolve();
            let ratio = contrast_ratio(fg, bg);
            assert!(ratio >= 4.5, "Color {:?} has ratio {} < 4.5", color, ratio);
        }
    }
}
```

